// Extraer datos del webhook usando sintaxis de nodo
const sessionId = $node["Webhook"].json.body.sessionId || '';
const companyId = $node["Webhook"].json.body.company_id || null;
const userMessage = $node["Webhook"].json.body.user_message || '';
const step = $node["Webhook"].json.body.vc_step || '';

// Extraer datos del cliente
const client = $node["Webhook"].json.body.client || {};
const clientId = client.Id || null;
const clientIdentification = client.vc_identification_number || '';
const clientPhone = client.vc_phone || '';
const clientNickName = client.vc_nick_name || '';
const clientFirstName = client.vc_first_name || '';
const clientEmail = client.vc_email || '';

// Retornar la data organizada
return {
  sessionId: sessionId,
  company_id: companyId,
  user_message: userMessage,
  step: step,
  client: {
    id: clientId,
    identification_number: clientIdentification,
    phone: clientPhone,
    nick_name: clientNickName,
    first_name: clientFirstName,
    email: clientEmail
  }
};

// Extraer la data de la respuesta HTTP
const response = $node["Professional-Context"].json;
const professionals = response.data || [];

// Función para formatear los horarios de manera legible
function formatSchedule(horarios) {
  return horarios.map(h => {
    let schedule = `${h.dia}: ${h.horaInicio} - ${h.horaFin}`;
    if (h.break) {
      schedule += ` (Break: ${h.break.inicio} - ${h.break.fin})`;
    }
    return schedule;
  }).join('\n    ');
}

// Función para formatear los servicios
function formatServices(servicios) {
  return servicios.map(s => `- ${s.service} (ID: ${s.service_id})`).join('\n    ');
}

// Crear el contexto formateado para el LLM
let context = `INFORMACIÓN DE PROFESIONALES DISPONIBLES\n`;
context += `===========================================\n\n`;
context += `Total de profesionales: ${professionals.length}\n\n`;

professionals.forEach((prof, index) => {
  context += `${index + 1}. ${prof.Nombre.toUpperCase()}\n`;
  context += `   ID Profesional: ${prof.Id}\n`;
  context += `   Profesión: ${prof.Profesion}\n`;
  context += `   Especialización: ${prof.Especializacion}\n`;
  context += `   Contacto: ${prof.Email} | ${prof.Telefono}\n\n`;

  context += `   SERVICIOS QUE OFRECE:\n`;
  context += `   ${formatServices(prof.Servicios)}\n\n`;

  context += `   HORARIOS DISPONIBLES:\n`;
  context += `   ${formatSchedule(prof.Horarios)}\n`;
  context += `\n${'─'.repeat(80)}\n\n`;
});

// Retornar tanto el contexto formateado como la data original
return {
  formatted_context: context,
  professionals_data: professionals,
  total_professionals: professionals.length
};

// Extraer la respuesta del modelo AI
const aiResponse = $node["Appointment"].json.output;

// Parsear el JSON que viene como string
const parsedResponse = JSON.parse(aiResponse);

// Extraer cada campo
const serviceId = parsedResponse.ServiceId || null;
const professionalId = parsedResponse.ProfessionalId || null;
const dtDate = parsedResponse.DtDate || null;
const tStartTime = parsedResponse.TStartTime || null;
const step = parsedResponse.step || '';
const message = parsedResponse.message || '';

// Retornar la data parseada y organizada
return {
  // Datos de la cita
  appointment: {
    ServiceId: serviceId,
    ProfessionalId: professionalId,
    DtDate: dtDate,
    TStartTime: tStartTime
  },

  // Estado del flujo
  step: step,

  // Mensaje para el usuario
  message: message,

  // Flag para saber si está completo
  is_complete: serviceId !== null && professionalId !== null && dtDate !== null && tStartTime !== null,
};
